import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const nodeModulesPath = path.resolve(__dirname, '../../node_modules/cubejs/lib');
const outputPath = path.resolve(__dirname, 'cubejs-local.js');

let cubeContent = fs.readFileSync(path.join(nodeModulesPath, 'cube.js'), 'utf8');
let solveContent = fs.readFileSync(path.join(nodeModulesPath, 'solve.js'), 'utf8');

// Strip the outer IIFE wrapper: (function() { ... }).call(this);
// and replace `.call(this)` with `.call(ns)` so `this` doesn't break in strict mode
cubeContent = cubeContent
  // Remove the outer IIFE call wrapper (last line)
  .replace(/\}\)\.call\(this\);\s*$/, '}).call(ns);')
  // Strip the CJS/global export block at the end of cube.js
  .replace(
    /\/\/# Globals[\s\S]*?(?:module\.exports\s*=\s*Cube;[\s\S]*?this\.Cube\s*=\s*Cube;\s*\})/,
    'ns.Cube = Cube;'
  );

solveContent = solveContent
  .replace(/\}\)\.call\(this\);\s*$/, '}).call(ns);')
  // solve.js reads Cube from `this.Cube || require('./cube')`
  .replace(/Cube\s*=\s*this\.Cube \|\| require\(['"]\.\/cube['"]\);/, 'Cube = ns.Cube;');

const output = `/**
 * cubejs — patched ES-module bundle (worker-safe, no CJS).
 * Auto-generated by bundle_cubejs.js — do not edit by hand.
 */

// Shared namespace object that replaces top-level \`this\` in the IIFEs.
const ns = Object.create(null);

${cubeContent}

${solveContent}

export default ns.Cube;
`;

fs.writeFileSync(outputPath, output, 'utf8');
console.log('✓ cubejs-local.js written to', outputPath);
